settings.custom_liquid:
{% if product.available %}
<div style="text-align: center;">
  <div class="instock-pulse">
    <span class="icon--pulsing"></span>
    <span id="low-stock-message" style="color: #000;">Low Stock (BIG SALE Till Midnight Only!)</span>
  </div>



  <style>
    .instock-pulse {
      display: flex;
      flex-wrap: nowrap;
      align-items: center;
      justify-content: center;
    }

    .icon--pulsing {
      position: relative;
      width: 20px;
      height: 20px;
      margin-right: 10px;
    }

    .icon--pulsing:after,
    .icon--pulsing:before {
      background: #F4AF29;
      width: 10px;
      height: 10px;
      border-radius: 10px;
      position: absolute;
      left: 0;
      top: 0;
      content: "";
      margin: 5px;
    }

    @keyframes inventory-pulse {
      0% {
        opacity: 0.5;
      }
      to {
        transform: scale(2.5);
        opacity: 0;
      }
    }

    .icon--pulsing:before {
      animation: inventory-pulse 2s linear infinite;
    }

    /* Media Query for Font Size on Mobile */
    @media (max-width: 768px) {
      #low-stock-message {
        font-size: 16px;
      }
    }
  </style>
</div>
{% endif %}

{% if product.available %}
<div style="text-align: center;">
  <div class="instock-pulse">
    <span class="icon--pulsing"></span>
    <span id="low-stock-message" style="color: #000;">Low stock (loading...)</span>
  </div>

  <script>
    document.addEventListener('DOMContentLoaded', function() {
      var lowStockMessage = document.getElementById('low-stock-message');

      function updateLowStockMessage() {
        var storedTimestamp = localStorage.getItem('lowStockTimestamp');
        var currentTime = new Date().getTime();
        var timeDifference = currentTime - storedTimestamp;

        if (!storedTimestamp || timeDifference > 30 * 60 * 1000) {
          var random_number = Math.floor(Math.random() * 20) + 1;
          localStorage.setItem('lowStockRandomNumber', random_number);
          localStorage.setItem('lowStockTimestamp', currentTime);
        }

        var storedRandomNumber = localStorage.getItem('lowStockRandomNumber');

        // Check if the URL contains "/de"
        var urlContainsDE = window.location.href.indexOf('/de') !== -1;

        if (urlContainsDE) {
          lowStockMessage.textContent = 'Niedriger Lagerbestand (' + storedRandomNumber + ' Stücke übrig)';
        } else {
          lowStockMessage.textContent = 'Low stock (' + storedRandomNumber + ' pieces left)';
        }
      }

      updateLowStockMessage();

      // You'll need to add an event listener for variant selection.
      // This code assumes that you're using jQuery and the 'variantSelect' element.
      $('.variantSelect').on('change', function() {
        updateLowStockMessage();
      });
    });
  </script>

  <style>
    .instock-pulse {
      display: flex;
      flex-wrap: nowrap;
      align-items: center;
      justify-content: center;
    }

    .icon--pulsing {
